script.text:

function active$SalaryAdjustment(f) {
  f.add_onResponseComplete(on$SalaryAdjustment$ResponseComplete);
  init$SalaryAdjustment(f);
}
function scatter$SalaryAdjustment(f) {init$SalaryAdjustment(f);}
function close$SalaryAdjustment(f) {try {f.remove_onResponseComplete(on$SalaryAdjustment$ResponseComplete)} catch (ex) {}}
function onchange$SalaryAdjustment$IDNumber(o) {o.parentForm.request('IDNumber', 'IDNumber', ['ma_nv']);}
function on$SalaryAdjustment$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
		case 'Checking':
      break;
    case 'IDNumber':
      f.setItemControlBehavior('stt_rec', result[0].Value, true);
      break;
    default:
      break;
  }
}
function init$SalaryAdjustment(f) {
  var g = f.grid;
  f.setItemValues('ky, nam', [g._ky, g._nam]);
  f.getItem('ky').disabled = true;
  f.getItem('nam').disabled = true;
  f.getItem('ma_nv').focus();
}
